description:
Implement PromptWorld - the central type universe + renderer registry + Jinja environment + settings container.

Location: crates/baml-bridge/src/prompt/world.rs

```rust
use std::sync::Arc;
use minijinja::Environment;

/// The prompt rendering universe
pub struct PromptWorld {
    /// Type information database
    pub types: TypeDb,

    /// Compiled renderers
    pub renderers: RendererDb,

    /// Configured Jinja environment for prompt rendering
    pub jinja: Environment<'static>,

    /// Default render settings
    pub settings: RenderSettings,

    /// Union resolution strategy
    pub union_resolver: UnionResolver,
}

impl PromptWorld {
    /// Construct from registry output
    pub fn from_registry(
        output_format: OutputFormatContent,
        renderer_seed: RendererDbSeed,
        settings: RenderSettings,
    ) -> Result<Self, RenderError> {
        // 1. Build TypeDb from OutputFormatContent arcs
        let types = TypeDb {
            enums: output_format.enums.clone(),
            classes: output_format.classes.clone(),
            structural_recursive_aliases: output_format.structural_recursive_aliases.clone(),
            recursive_classes: output_format.recursive_classes.clone(),
        };

        // 2. Start with base Jinja environment
        let mut jinja = crate::jsonish::jinja_helpers::get_env();

        // 3. Configure strict undefined behavior
        jinja.set_undefined_behavior(minijinja::UndefinedBehavior::Strict);

        // 4. Install custom formatter for JinjaPromptValue
        // (handled in jinja.rs)

        // 5. Compile renderer templates into environment
        let renderers = RendererDb::compile_from_seed(renderer_seed, &mut jinja)?;

        // 6. Add prompt-specific filters
        // truncate, slice_chars, format_count

        Ok(Self {
            types,
            renderers,
            jinja,
            settings,
            union_resolver: default_union_resolver,
        })
    }
}
```

Key decisions implemented:
- Strict undefined behavior (no silent missing fields)
- Templates compiled into env by name
- Default union resolver used
